import{_ as e,o as t,c as o,ag as n}from"./chunks/framework.BZohXCq9.js";const c=JSON.parse('{"title":"老张餐馆","description":"","frontmatter":{"title":"老张餐馆","outline":false},"headers":[],"relativePath":"novels/lao-zhang-restaurant/index.md","filePath":"novels/lao-zhang-restaurant/index.md","lastUpdated":1775283989000}'),r={name:"novels/lao-zhang-restaurant/index.md"};function l(s,a,i,h,p,d){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="老张餐馆" tabindex="-1">老张餐馆 <a class="header-anchor" href="#老张餐馆" aria-label="Permalink to &quot;老张餐馆&quot;">​</a></h1><blockquote><p>一个被AI淘汰的程序员，回到十八线县城，接手父亲的小餐馆 风格：温暖现实主义 + 黑色幽默 + 荒诞喜剧</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>张建国，40岁，北京某软件公司首席架构师。十五年的代码，抵不过AI的一次迭代。裁员通知单上的数字，就是他在这个行业的全部身价。</p><p>他有房贷、车贷、一个在北京上学的儿子，和一个越来越沉默的妻子。</p><p>老家——一个十八线小县城的老城区——父亲开了三十年的&quot;张记面馆&quot;快撑不下去了。老城萧条，新城繁华，一座县城像被劈成了两半。</p><p>老张回来了。不是衣锦还乡，是走投无路。</p><p>和他一起守着这个破餐馆的，还有：一个混过江湖但啥也没混成的弟弟，一个倔得像灶台上的铁锅的老爹，一个话不多但刀工二十年如一日的老厨师，和一个梦想当网红的服务员。</p><p>餐馆是个舞台。拆迁户、外卖骑手、预制菜老板娘、城管、钉子户、返乡青年……县城的人来了又走，每个人都带着自己的故事。</p><p>这不是一个逆袭的故事。这是一个关于&quot;明天还开门&quot;的故事。</p><h2 id="章节目录" tabindex="-1">章节目录 <a class="header-anchor" href="#章节目录" aria-label="Permalink to &quot;章节目录&quot;">​</a></h2><p><em>即将更新</em></p><h2 id="项目资料" tabindex="-1">项目资料 <a class="header-anchor" href="#项目资料" aria-label="Permalink to &quot;项目资料&quot;">​</a></h2><ul><li><a href="/novels/lao-zhang-restaurant/pitch.html"><strong>项目路演</strong></a> — 完整的项目介绍、受众分析与执行计划</li><li><a href="/novels/lao-zhang-restaurant/behind-the-scenes/outline.html">故事大纲</a> — 14集分集大纲与人物设定</li></ul>',14)])])}const _=e(r,[["render",l]]);export{c as __pageData,_ as default};
